// ─── evaluateMetricLevel ─────────────────────────────────────────────

describe('evaluateMetricLevel', () => {
  const thresholds = { warning: 80, critical: 95 };

  it('should return healthy when below warning', () => {
    expect(evaluateMetricLevel(50, thresholds)).toBe('healthy');
  });

  it('should return warning when at warning threshold', () => {
    expect(evaluateMetricLevel(80, thresholds)).toBe('warning');
  });

  it('should return critical when at critical threshold', () => {
    expect(evaluateMetricLevel(95, thresholds)).toBe('critical');
  });

  it('should return critical when above critical', () => {
    expect(evaluateMetricLevel(99, thresholds)).toBe('critical');
  });

  // Inverted mode (higher is better, like success rate)
  it('should use inverted thresholds for success rate', () => {
    expect(evaluateMetricLevel(99, HEALTH_THRESHOLDS.apiSuccessRate, true)).toBe('healthy');
  });

  it('should return warning for inverted below warning', () => {
    expect(evaluateMetricLevel(93, HEALTH_THRESHOLDS.apiSuccessRate, true)).toBe('warning');
  });

  it('should return critical for inverted below critical', () => {
    expect(evaluateMetricLevel(85, HEALTH_THRESHOLDS.apiSuccessRate, true)).toBe('critical');
  });
});

// ─── evaluateServiceHealth ───────────────────────────────────────────

describe('evaluateServiceHealth', () => {
  const baseService: ServiceStatus = {
    name: 'TestService',
    state: 'healthy',
    latencyMs: 10,
    lastChecked: new Date().toISOString(),
    message: null,
  };

  it('should return healthy for low latency', () => {
    expect(evaluateServiceHealth({ ...baseService, latencyMs: 10 })).toBe('healthy');
  });

  it('should return degraded for moderate latency', () => {
    expect(evaluateServiceHealth({ ...baseService, latencyMs: 500 })).toBe('degraded');
  });

  it('should return down for extreme latency', () => {
    expect(evaluateServiceHealth({ ...baseService, latencyMs: 1500 })).toBe('down');
  });

  it('should preserve down state', () => {
    expect(evaluateServiceHealth({ ...baseService, state: 'down', latencyMs: 5 })).toBe('down');
  });

  it('should handle null latency', () => {
    expect(evaluateServiceHealth({ ...baseService, state: 'unknown', latencyMs: null })).toBe('unknown');
  });
});

// ─── computeOverallHealth ────────────────────────────────────────────

describe('computeOverallHealth', () => {
  function buildData(overrides: Partial<Omit<HealthDashboardData, 'overall'>> = {}): Omit<HealthDashboardData, 'overall'> {
    return {
      timestamp: new Date().toISOString(),
      uptime: { startedAt: new Date().toISOString(), uptimeSeconds: 86400, formatted: '1d' },
      services: [
        { name: 'DB', state: 'healthy', latencyMs: 10, lastChecked: new Date().toISOString(), message: null },
      ],
      api: {
        totalRequests: 1000,
        successRate: 99.5,
        errorRate: 0.5,
        avgLatencyMs: 100,
        p95LatencyMs: 200,
        p99LatencyMs: 400,
        topEndpoints: [],
        errorsByStatus: {},
      },
      queue: {
        activeJobs: 1,
        waitingJobs: 2,
        completedJobs: 100,
        failedJobs: 1,
        delayedJobs: 0,
        avgProcessingTimeMs: 5000,
        throughputPerMinute: 3,
      },
      storage: {
        totalUsedBytes: 1_000_000,
        totalFiles: 100,
        breakdown: {},
        quotaBytes: 10_000_000,
        usagePercent: 10,
      },
      system: {
        nodeVersion: 'v20.0.0',
        memoryUsedMB: 256,
        memoryTotalMB: 1024,
        memoryPercent: 25,
        cpuUsagePercent: 20,
        activeConnections: 10,
      },
      ...overrides,
    };
  }

  it('should return healthy with all healthy metrics', () => {
    const result = computeOverallHealth(buildData());
    expect(result.level).toBe('healthy');
    expect(result.score).toBeGreaterThan(80);
    expect(result.issues).toHaveLength(0);
  });

  it('should return warning when API success rate is degraded', () => {
    const result = computeOverallHealth(
      buildData({ api: { ...buildData().api, successRate: 93, errorRate: 7 } }),
    );
    expect(result.level).toBe('warning');
    expect(result.issues.length).toBeGreaterThan(0);
    expect(result.issues.some((i) => i.component === 'API')).toBe(true);
  });

  it('should return critical when service is down', () => {
    const result = computeOverallHealth(
      buildData({
        services: [
          { name: 'DB', state: 'down', latencyMs: null, lastChecked: new Date().toISOString(), message: 'Connection refused' },
        ],
      }),
    );
    expect(result.level).toBe('critical');
    expect(result.issues.some((i) => i.severity === 'critical')).toBe(true);
  });

  it('should collect issues from multiple components', () => {
    const result = computeOverallHealth(
      buildData({
        api: { ...buildData().api, successRate: 85, errorRate: 15 },
        system: { ...buildData().system, memoryPercent: 97 },
      }),
    );
    expect(result.issues.length).toBeGreaterThanOrEqual(2);
    const components = result.issues.map((i) => i.component);
    expect(components).toContain('API');
    expect(components).toContain('System');
  });
});

// ─── computeTrend ────────────────────────────────────────────────────

describe('computeTrend', () => {
  it('should detect upward trend', () => {
    const trend = computeTrend(120, 100);
    expect(trend.direction).toBe('up');
    expect(trend.changePercent).toBe(20);
  });

  it('should detect downward trend', () => {
    const trend = computeTrend(80, 100);
    expect(trend.direction).toBe('down');
    expect(trend.changePercent).toBe(-20);
  });

  it('should detect stable', () => {
    const trend = computeTrend(100, 100);
    expect(trend.direction).toBe('stable');
    expect(trend.changePercent).toBe(0);
  });

  it('should handle previous = 0', () => {
    const trend = computeTrend(50, 0);
    expect(trend.direction).toBe('up');
    expect(trend.changePercent).toBe(100);
  });

  it('should handle both zero', () => {
    const trend = computeTrend(0, 0);
    expect(trend.direction).toBe('stable');
    expect(trend.changePercent).toBe(0);
  });
});

// ─── calculateHealthScore ────────────────────────────────────────────

describe('calculateHealthScore', () => {
  it('should return high score for perfect health', () => {
    const score = calculateHealthScore({
      apiSuccessRate: 100,
      servicesHealthy: 5,
      totalServices: 5,
      queueFailedPercent: 0,
      memoryPercent: 30,
    });
    expect(score).toBeGreaterThan(90);
  });

  it('should return lower score for degraded services', () => {
    const score = calculateHealthScore({
      apiSuccessRate: 95,
      servicesHealthy: 3,
      totalServices: 5,
      queueFailedPercent: 5,
      memoryPercent: 70,
    });
    expect(score).toBeLessThan(90);
    expect(score).toBeGreaterThan(50);
  });

  it('should return low score for critical state', () => {
    const score = calculateHealthScore({
      apiSuccessRate: 70,
      servicesHealthy: 1,
      totalServices: 5,
      queueFailedPercent: 20,
      memoryPercent: 96,
    });
    expect(score).toBeLessThan(60);
  });
});

