// ─── groupErrorsByStatus ─────────────────────────────────────────────

describe('groupErrorsByStatus', () => {
  it('should group mixed errors correctly', () => {
    const result = groupErrorsByStatus({ 400: 5, 404: 3, 500: 2, 503: 1 });
    expect(result.client).toBe(8);
    expect(result.server).toBe(3);
    expect(result.total).toBe(11);
  });

  it('should handle only client errors', () => {
    const result = groupErrorsByStatus({ 400: 10, 401: 5 });
    expect(result.client).toBe(15);
    expect(result.server).toBe(0);
    expect(result.total).toBe(15);
  });

  it('should handle only server errors', () => {
    const result = groupErrorsByStatus({ 500: 3, 502: 1 });
    expect(result.client).toBe(0);
    expect(result.server).toBe(4);
    expect(result.total).toBe(4);
  });

  it('should handle empty object', () => {
    const result = groupErrorsByStatus({});
    expect(result.client).toBe(0);
    expect(result.server).toBe(0);
    expect(result.total).toBe(0);
  });
});

// ─── getMockDashboardData ────────────────────────────────────────────

describe('getMockDashboardData', () => {
  it('should return valid structure with all fields', () => {
    const data = getMockDashboardData();
    expect(data.timestamp).toBeDefined();
    expect(data.uptime).toBeDefined();
    expect(data.uptime.formatted).toBeTruthy();
    expect(data.services).toBeInstanceOf(Array);
    expect(data.services.length).toBeGreaterThan(0);
    expect(data.api).toBeDefined();
    expect(data.queue).toBeDefined();
    expect(data.storage).toBeDefined();
    expect(data.system).toBeDefined();
    expect(data.overall).toBeDefined();
  });

  it('should have computed overall health', () => {
    const data = getMockDashboardData();
    expect(data.overall.level).toBeDefined();
    expect(data.overall.score).toBeGreaterThanOrEqual(0);
    expect(data.overall.score).toBeLessThanOrEqual(100);
    expect(data.overall.issues).toBeInstanceOf(Array);
  });

  it('should have all five services', () => {
    const data = getMockDashboardData();
    const names = data.services.map((s) => s.name);
    expect(names).toContain('PostgreSQL');
    expect(names).toContain('Redis');
    expect(names).toContain('Supabase Auth');
    expect(names).toContain('S3/Storage');
    expect(names).toContain('Stripe');
  });
});

